#include<bits/stdc++.h>
using namespace std;
int n,c;
bool f(int a) {
	for(int i=sqrt(a)-1; i<=sqrt(a); i++)if(i*i==a)return true;
	return false;
}
int main() {
	cin>>n;
	for(int i=1; i<n; i++) {
		for(int j=i; j<n; j++) {
			if(f(i*i+j*j)&&i*i+j*j<=n*n) {
				c++;
			}
		}
	}
	cout<<c;
}
